import React, { useEffect, useState } from 'react';
import axios from 'axios';

export default function CrudPeriodos() {
  const [periodos, setPeriodos] = useState([]);
  const [nome, setNome] = useState('');
  const [turno, setTurno] = useState('Diurno');
  const [editando, setEditando] = useState(null);
  const [mensagem, setMensagem] = useState('');

  const fetchPeriodos = () => {
    axios.get('/api/periodos').then(res => setPeriodos(res.data));
  };

  useEffect(() => { fetchPeriodos(); }, []);

  const handleSubmit = e => {
    e.preventDefault();
    if (!nome) return setMensagem('Informe o nome do período');
    if (editando) {
      axios.put(`/api/periodos/${editando}`, { nome, turno })
        .then(() => {
          setMensagem('Período atualizado!');
          setEditando(null);
          setNome('');
          setTurno('Diurno');
          fetchPeriodos();
        });
    } else {
      axios.post('/api/periodos', { nome, turno })
        .then(() => {
          setMensagem('Período criado!');
          setNome('');
          setTurno('Diurno');
          fetchPeriodos();
        });
    }
  };

  const handleEditar = p => {
    setEditando(p.id);
    setNome(p.nome);
    setTurno(p.turno);
    setMensagem('');
  };

  const handleDeletar = id => {
    if (window.confirm('Deseja excluir este período?')) {
      axios.delete(`/api/periodos/${id}`).then(() => fetchPeriodos());
    }
  };

  return (
    <div className="bg-white rounded-xl p-8 shadow max-w-lg mx-auto mt-8">
      <h2 className="text-2xl font-bold mb-6">{editando ? 'Editar Período' : 'Novo Período'}</h2>
      <form onSubmit={handleSubmit} className="mb-6 flex flex-col gap-3">
        <input
          className="border rounded px-3 py-2"
          value={nome}
          placeholder="Ex: 2024/1"
          onChange={e => setNome(e.target.value)}
        />
        <select
          className="border rounded px-3 py-2"
          value={turno}
          onChange={e => setTurno(e.target.value)}
        >
          <option value="Diurno">Diurno</option>
          <option value="Noturno">Noturno</option>
        </select>
        <button className="bg-blue-600 text-white px-4 py-2 rounded">{editando ? 'Salvar' : 'Cadastrar'}</button>
        {editando && (
          <button type="button" className="bg-gray-400 text-white px-4 py-2 rounded" onClick={() => {
            setEditando(null); setNome(''); setTurno('Diurno'); setMensagem('');
          }}>Cancelar</button>
        )}
        {mensagem && <div className="text-green-600">{mensagem}</div>}
      </form>
      <table className="min-w-full rounded">
        <thead>
          <tr>
            <th className="px-3 py-2 text-left">Nome</th>
            <th className="px-3 py-2 text-left">Turno</th>
            <th className="px-3 py-2 text-left"></th>
          </tr>
        </thead>
        <tbody>
          {periodos.map(p => (
            <tr key={p.id}>
              <td className="px-3 py-2">{p.nome}</td>
              <td className="px-3 py-2">{p.turno}</td>
              <td className="px-3 py-2 flex gap-2">
                <button className="text-blue-600" onClick={() => handleEditar(p)}>Editar</button>
                <button className="text-red-600" onClick={() => handleDeletar(p.id)}>Excluir</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
